class Solution:
    def maximumSubsequenceCount(self, text, pattern):
        best = 0
        n = len(text)
        for pos in range(n + 1):
            for ch in set(pattern):
                candidate = text[:pos] + ch + text[pos:]
                count = 0
                seen_first = 0
                for c in candidate:
                    if c == pattern[0]:
                        seen_first += 1
                    if c == pattern[1]:
                        count += seen_first
                best = max(best, count)
        return best

