class Solution:
    def maximumSubsequenceCount(self, text, pattern):
        p0, p1 = pattern[0], pattern[1]
        base = 0
        seen_first = 0
        count_p0 = 0
        count_p1 = 0
        for c in text:
            if c == p0:
                seen_first += 1
                count_p0 += 1
            if c == p1:
                base += seen_first
                count_p1 += 1
        return base + max(count_p0, count_p1)

