var maximumSubsequenceCount = function(text, pattern) {
    const p0 = pattern[0], p1 = pattern[1];
    let base = 0, seenFirst = 0, countP0 = 0, countP1 = 0;
    for (const c of text) {
        if (c === p0) {
            seenFirst++;
            countP0++;
        }
        if (c === p1) {
            base += seenFirst;
            countP1++;
        }
    }
    return base + Math.max(countP0, countP1);
};
